import React from 'react'
import { Avatar, Layout, Menu } from 'antd';
import { CommentOutlined, TeamOutlined } from "@ant-design/icons"
const { Header } = Layout;

const items = [
  {
    label: 'Chat',
    key: 'chat',
    icon: <CommentOutlined />
  },
  {
    label: 'Contacts',
    key:'contacts',
    icon:<TeamOutlined/>
  }
]


export default function Bar() {
  const navigator = U
  return (
    <Header
      style={{
        width:"100%",
        display:'flex',
        alignItems: 'center',
        justifyContent:'space-between',
        backgroundColor: 'rgb(100,100,100,0.8)',
        borderBottom: "1px solid black",
      }}
    >
      <Menu items={items} style={{marginLeft:"100px",backgroundColor:"transparent",fontSize:'18px'}} backgroundColor="transparent" mode='horizontal'/>
      <Avatar size={50} style={{float:'right',marginRight:'30px'}} onClick={navigator(`/${items.keys}`)}>User</Avatar>
    </Header>
  )
}
